import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate, Vec3 } from 'cc';
import { GameManager } from '../Core/GameManager';
import { SceneConfig } from '../Config/SceneConfig';

const { ccclass, property } = _decorator;

@ccclass('MapScene')
export class MapScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Node)
    domainNodePrefab: Node = null;
    
    @property(Node)
    mapContainer: Node = null;
    
    @property(Label)
    currentLocationLabel: Label = null;
    
    private domains = SceneConfig.domains;
    private currentDomain: string = 'zishi';
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
    }
    
    start() {
        this.initMap();
        this.updateLocation();
    }
    
    initMap() {
        const domainKeys = Object.keys(this.domains);
        const positions = [
            new Vec3(-200, 200, 0),   // 子时
            new Vec3(0, 200, 0),      // 丑时
            new Vec3(200, 200, 0),    // 寅时
            new Vec3(-200, 50, 0),    // 卯时
            new Vec3(0, 50, 0),       // 辰时
            new Vec3(200, 50, 0),     // 巳时
            new Vec3(-200, -100, 0),  // 午时
            new Vec3(0, -100, 0),     // 未时
            new Vec3(200, -100, 0),   // 申时
            new Vec3(-200, -250, 0),  // 酉时
            new Vec3(0, -250, 0),     // 戌时
            new Vec3(200, -250, 0)    // 亥时
        ];
        
        for (let i = 0; i < domainKeys.length; i++) {
            const domainId = domainKeys[i];
            const domain = this.domains[domainId];
            
            const node = instantiate(this.domainNodePrefab);
            node.setPosition(positions[i]);
            
            // 设置名称
            node.getChildByName('NameLabel').getComponent(Label).string = domain.name;
            
            // 设置等级范围
            node.getChildByName('LevelLabel').getComponent(Label).string = domain.levelRange;
            
            // 点击事件
            const btn = node.getComponent(Button);
            btn.node.on(Button.EventType.CLICK, () => this.onDomainClick(domainId), this);
            
            this.mapContainer.addChild(node);
        }
    }
    
    onDomainClick(domainId: string) {
        const domain = this.domains[domainId];
        const playerLevel = GameManager.getInstance().playerData.getLevel();
        
        // 解析等级范围
        const [minLevel, maxLevel] = domain.levelRange.split('-').map(n => parseInt(n));
        
        if (playerLevel < minLevel) {
            // 等级不足提示
            console.log(`需要等级${minLevel}才能进入`);
            return;
        }
        
        // 保存当前选择的财域
        this.currentDomain = domainId;
        
        // 进入财域场景
        director.loadScene('DomainScene');
    }
    
    updateLocation() {
        const domain = this.domains[this.currentDomain];
        this.currentLocationLabel.string = `当前位置: ${domain.name}`;
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
